from shiny import App, ui, reactive, render
from gtts import gTTS
from pathlib import Path
import tempfile
import threading
import time
import pygame

pygame.mixer.init()

app_ui = ui.page_fluid(
    ui.h2("Português do Brasil - Hörtrainer"),
    ui.p(
        "Gib einen Satz ein und klicke auf 'Play'. "
        "Die Ausgabe wird serverseitig im brasilianischen Portugiesisch abgespielt."
    ),
    ui.input_text_area(
        "text",
        "Text zum Anhören",
        value="Olá! Tudo bem? Eu quero praticar português do Brasil.",
        rows=6,
        placeholder="Schreibe hier deinen portugiesischen Text ..."
    ),
    ui.input_action_button("play", "Play"),
    ui.hr(),
    ui.output_text_verbatim("status")
)

def server(input, output, session):
    status_text = reactive.value("Bereit.")

    def speak_text(text: str):
        mp3_path = None
        try:
            status_text.set("Erzeuge Audio mit gTTS ...")

            with tempfile.NamedTemporaryFile(delete=False, suffix=".mp3") as tmp:
                mp3_path = Path(tmp.name)

            tts = gTTS(text=text, lang="pt", tld="com.br")
            tts.save(str(mp3_path))

            status_text.set("Spiele Audio serverseitig ab ...")

            pygame.mixer.music.stop()
            pygame.mixer.music.unload()
            pygame.mixer.music.load(str(mp3_path))
            pygame.mixer.music.play()

            while pygame.mixer.music.get_busy():
                time.sleep(0.1)

            status_text.set("Fertig.")
        except Exception as e:
            status_text.set(f"Fehler: {e}")
        finally:
            try:
                pygame.mixer.music.unload()
            except Exception:
                pass

            try:
                if mp3_path and mp3_path.exists():
                    mp3_path.unlink()
            except Exception:
                pass

    @reactive.effect
    @reactive.event(input.play)
    def _play_audio():
        text = input.text().strip()

        if not text:
            status_text.set("Bitte gib zuerst einen Text ein.")
            return

        thread = threading.Thread(target=speak_text, args=(text,), daemon=True)
        thread.start()

    @output
    @render.text
    def status():
        return status_text.get()

app = App(app_ui, server)
